mapper.select:
SELECT i.id, i.snapshot_id, i.fund_asset_id, i.fund_code, i.fund_name, i.buy_status, i.daily_purchase_limit, i.returns_as_of, i.top_holdings_as_of, i.public_holdings_status, i.one_month_return, i.three_months_return, i.six_months_return, i.one_year_return, i.three_years_return, i.field_sources_json, i.missing_reasons_json, i.create_time, i.update_time FROM fund_detail_item i JOIN fund_detail_snapshot s ON s.id = i.snapshot_id WHERE i.fund_code IN
#{fundCode}
AND s.snapshot_status IN ('succeeded', 'partial_failed', 'success', 'partial') AND i.id = ( SELECT ii.id FROM fund_detail_item ii JOIN fund_detail_snapshot ss ON ss.id = ii.snapshot_id WHERE ii.fund_code = i.fund_code AND ss.snapshot_status IN ('succeeded', 'partial_failed', 'success', 'partial') ORDER BY ss.generated_at DESC, ii.id DESC LIMIT 1 ) ORDER BY i.fund_code ASC
